package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringReader;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithSkipHeaderRecord() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withSkipHeaderRecord();

        // Then
        assertTrue(result.getSkipHeaderRecord());
    }

    @Test
    public void testWithSkipHeaderRecordFalse() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withSkipHeaderRecord(false);

        // Then
        assertFalse(result.getSkipHeaderRecord());
    }

    @Test
    public void testWithSkipHeaderRecordUsingReflection() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = invokePrivateMethod(csvFormat, "withSkipHeaderRecord", boolean.class, false);

        // Then
        assertFalse(result.getSkipHeaderRecord());
    }

    private <T> T invokePrivateMethod(Object object, String methodName, Class<?> parameterType, Object argument) throws Exception {
        java.lang.reflect.Method method = object.getClass().getDeclaredMethod(methodName, parameterType);
        method.setAccessible(true);
        return (T) method.invoke(object, argument);
    }
}
